#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int *islands = (int *)malloc(N * sizeof(int));
        int *ingredients = (int *)malloc(K * sizeof(int));
        memset(ingredients, 0, K * sizeof(int));
        int allCollected = 0;
        int allIslandsVisited = 0;
        for (int i = 0; i < N; i++) {
            int Pi;
            scanf("%d", &Pi);
            islands[i] = Pi;
            for (int j = 0; j < Pi; j++) {
                int ingredient;
                scanf("%d", &ingredient);
                ingredients[ingredient - 1] = 1;
            }
            allIslandsVisited++;
            int collected = 0;
            for (int j = 0; j < K; j++) {
                if (ingredients[j]) collected++;
            }
            if (collected == K) {
                allCollected = 1;
                break;
            }
        }
        if (allCollected == 0) printf("sad\n");
        else if (allIslandsVisited < N) printf("some\n");
        else printf("all\n");
        free(islands);
        free(ingredients);
    }
    return 0;
}

