import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            int[] islands = new int[N];
            int[] ingredients = new int[K];
            int allCollected = 0;
            int allIslandsVisited = 0;
            for (int i = 0; i < N; i++) {
                int Pi = scanner.nextInt();
                islands[i] = Pi;
                for (int j = 0; j < Pi; j++) {
                    int ingredient = scanner.nextInt();
                    ingredients[ingredient - 1] = 1;
                }
                allIslandsVisited++;
                int collected = 0;
                for (int j = 0; j < K; j++) {
                    if (ingredients[j] == 1) collected++;
                }
                if (collected == K) {
                    allCollected = 1;
                    break;
                }
            }
            if (allCollected == 0) System.out.println("sad");
            else if (allIslandsVisited < N) System.out.println("some");
            else System.out.println("all");
        }
    }
}

code.JavaScript:
const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, K] = readline().split(' ').map(Number);
    const islands = [];
    const ingredients = new Array(K).fill(0);
    let allCollected = 0;
    let allIslandsVisited = 0;
    for (let j = 0; j < N; j++) {
        const Pi = parseInt(readline().split(' ')[0]);
        const ingredientsList = readline().split(' ').slice(1).map(Number);
        islands.push(Pi);
        for (const ingredient of ingredientsList) {
            ingredients[ingredient - 1] = 1;
        }
        allIslandsVisited++;
        const collected = ingredients.filter(x => x).length;
        if (collected === K) {
            allCollected = 1;
            break;
        }
    }
    if (allCollected === 0) console.log('sad');
    else if (allIslandsVisited < N) console.log('some');
    else console.log('all');
}

